     1→/**
     2→ * useGearEditor Hook
     3→ *
     4→ * Feature: 001-gear-item-editor
     5→ * Updated: 005-loadout-management - Migrated to use zustand store
     6→ * Updated: 037-final-stabilization - Error recovery and MIME sanitization
     7→ * Constitution: All form/business logic MUST reside in hooks
     8→ *
     9→ * Handles form state, validation, submission, and entity conversion
    10→ * for the Gear Item Editor.
    11→ */
    12→
    13→'use client';
    14→
    15→import { useCallback, useEffect, useMemo, useState } from 'react';
    16→import { useForm } from 'react-hook-form';
    17→import { zodResolver } from '@hookform/resolvers/zod';
    18→import { useRouter } from '@/i18n/navigation';
    19→import { toast } from 'sonner';
    20→
    21→import type { GearItem, GearItemFormData } from '@/types/gear';
    22→import { DEFAULT_GEAR_ITEM_FORM } from '@/types/gear';
    23→import { gearItemFormSchema } from '@/lib/validations/gear-schema';
    24→import {
    25→  gearItemToFormData,
