    30→import { useCloudinaryUpload } from '@/hooks/useCloudinaryUpload';
    31→import { useWishlist } from '@/hooks/useWishlist';
    32→import {
    33→  useDuplicateDetection,
    34→  type UseDuplicateDetectionReturn,
    35→} from '@/hooks/useDuplicateDetection';
    36→
    37→// =============================================================================
    38→// Image Import Helpers
    39→// =============================================================================
    40→
    41→/**
    42→ * Check if URL is external (needs import to Cloudinary)
    43→ * Skip Cloudinary URLs (already cloud-hosted)
    44→ */
    45→function isExternalUrl(url: string | null | undefined): boolean {
    46→  if (!url) return false;
    47→  if (!url.startsWith('http://') && !url.startsWith('https://')) return false;
    48→  // Skip Cloudinary URLs (already cloud-hosted, no need to import)
    49→  if (url.includes('res.cloudinary.com')) return false;
    50→  return true;
    51→}
    52→
    53→// =============================================================================
    54→// Types
    55→// =============================================================================
    56→
    57→export interface UseGearEditorOptions {
    58→  /** Existing gear item to edit (undefined for new item) */
    59→  initialItem?: GearItem;
    60→  /** Callback when save is successful */
    61→  onSaveSuccess?: (item: GearItem) => void;
    62→  /** Callback when save fails */
    63→  onSaveError?: (error: Error) => void;
    64→  /** Custom redirect path after save (default: /inventory) */
    65→  redirectPath?: string;
    66→  /** Mode for saving - inventory or wishlist (Feature 049) */
    67→  mode?: 'inventory' | 'wishlist';
    68→}
    69→
    70→export interface UseGearEditorReturn {
    71→  /** React Hook Form instance */
    72→  form: ReturnType<typeof useForm<GearItemFormData>>;
    73→  /** Whether the form is for editing (vs creating new) */
    74→  isEditing: boolean;
    75→  /** Whether the form has unsaved changes */
    76→  isDirty: boolean;
    77→  /** Whether form is currently submitting */
    78→  isSubmitting: boolean;
    79→  /** Whether image upload is in progress */
    80→  isUploading: boolean;
    81→  /** Whether delete operation is in progress */
    82→  isDeleting: boolean;
    83→  /** Handle form submission */
    84→  handleSubmit: (e?: React.BaseSyntheticEvent) => Promise<void>;
    85→  /** Handle cancel action */
    86→  handleCancel: () => void;
    87→  /** Reset form to initial values */
    88→  resetForm: () => void;
    89→  /** Handle delete action (only available when editing) */
    90→  handleDelete: () => Promise<void>;
    91→  /** Duplicate detection state and callbacks for DuplicateWarningDialog */
    92→  duplicateDetection: Pick<
    93→    UseDuplicateDetectionReturn,
    94→    | 'isOpen'
    95→    | 'bestMatch'
    96→    | 'isIncreasingQuantity'
    97→    | 'onConfirmSave'
    98→    | 'onCancel'
    99→    | 'onIncreaseQuantity'
   100→  >;

